import React,{useEffect,useMemo,useState}from"react";import{CheckCircle2,Search}from"lucide-react";import{vendorAPI,formatDate,safeArray}from"../../services/api.js";import{routeLabel}from"../../utils/mappers.js";import{useToast}from"../../components/ui/Toast.jsx";import Modal from"../../components/ui/Modal.jsx";import{CardPanel,DetailsGrid,PageHeader,StatusPill}from"../../components/ui/PortalUI.jsx";
export default function VendorCompletedJobsPage(){const{showToast}=useToast();const[jobs,setJobs]=useState([]);const[keyword,setKeyword]=useState("");const[selected,setSelected]=useState(null);useEffect(()=>{(async()=>{try{setJobs(safeArray(await vendorAPI.leads({status:"completed"})))}catch(e){showToast(e.message,"error")}})()},[]);const rows=useMemo(()=>jobs.filter(x=>{const m=x.move||x;return[m.job_id,m.pickup_postcode,m.delivery_postcode,m.status].filter(Boolean).join(" ").toLowerCase().includes(keyword.toLowerCase())}),[jobs,keyword]);return <div className="page-wrap"><PageHeader icon={CheckCircle2} title="Completed Jobs" subtitle="Historical work records and completed moves." search={keyword} onSearch={setKeyword}/><CardPanel title="Completed Jobs"><div className="table-scroll"><table><thead><tr><th>Job ID</th><th>Route</th><th>Move Date</th><th>Property</th><th>Status</th><th>Action</th></tr></thead><tbody>{rows.map(x=>{const m=x.move||x;return<tr key={x.id||m.id}><td><b>{m.job_id}</b></td><td>{routeLabel(m.pickup_postcode,m.delivery_postcode)}</td><td>{formatDate(m.moving_date)}</td><td>{m.property_size||"—"}</td><td><StatusPill value={m.status||"completed"}/></td><td><button className="tiny-btn" onClick={()=>setSelected(x)}>View</button></td></tr>})}</tbody></table>{!rows.length?<div className="empty-state">No completed jobs found.</div>:null}</div></CardPanel><Modal open={!!selected} title="Completed Job Details" onClose={()=>setSelected(null)} size="lg"><DetailsGrid rows={[["Job ID",(selected?.move||selected)?.job_id],["Route",routeLabel((selected?.move||selected)?.pickup_postcode,(selected?.move||selected)?.delivery_postcode)],["Move Date",formatDate((selected?.move||selected)?.moving_date)],["Property",(selected?.move||selected)?.property_size],["Status",(selected?.move||selected)?.status]]}/></Modal></div>}
